  function splitQueryPart(part) {
    const separatorIndex = part.indexOf('=');
    if (separatorIndex === -1) {
      return {
        key: decodeQueryComponent(part),
        value: '',
      };
    }

    return {
      key: decodeQueryComponent(part.slice(0, separatorIndex)),
      value: decodeQueryComponent(part.slice(separatorIndex + 1)),
    };
  }

